// src/Login.jsx
import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import Navbar from './Navbar'; // 👈 Importamos el Navbar

const Login = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [errors, setErrors] = useState({});
  const [flashMessage, setFlashMessage] = useState({ type: '', message: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const validateField = (name, value) => {
    const newErrors = { ...errors };
    switch (name) {
      case 'email':
        if (!value.trim()) newErrors.email = 'El email es requerido';
        else {
          const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
          if (!emailRegex.test(value)) newErrors.email = 'Ingresa un email válido';
          else delete newErrors.email;
        }
        break;
      case 'password':
        if (!value) newErrors.password = 'La contraseña es requerida';
        else if (value.length < 8) newErrors.password = 'Mínimo 8 caracteres';
        else delete newErrors.password;
        break;
      default: break;
    }
    setErrors(newErrors);
  };

  const validateForm = () => {
    const newErrors = {};
    if (!formData.email.trim()) newErrors.email = 'El email es requerido';
    else {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(formData.email)) newErrors.email = 'Ingresa un email válido';
    }
    if (!formData.password) newErrors.password = 'La contraseña es requerida';
    else if (formData.password.length < 8) newErrors.password = 'Mínimo 8 caracteres';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    validateField(name, value);
    if (flashMessage.message) setFlashMessage({ type: '', message: '' });
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    if (validateForm()) {
      try {
        await new Promise(resolve => setTimeout(resolve, 1000));
        if (formData.email === 'user@test.com' && formData.password === 'Password123') {
          setFlashMessage({ type: 'success', message: '¡Inicio de sesión exitoso!' });
          setFormData({ email: '', password: '' });
        } else {
          setFlashMessage({ type: 'error', message: 'Credenciales incorrectas' });
        }
      } catch {
        setFlashMessage({ type: 'error', message: 'Error del servidor. Intenta de nuevo.' });
      }
    } else {
      setFlashMessage({ type: 'error', message: 'Por favor corrige los errores' });
    }
    setIsSubmitting(false);
  };

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar /> {/* 👈 Aquí usamos el Navbar */}

      <div className="login-page">
        <div className="container-form">
          <div className="formulario">
            <h2 className="title">Iniciar Sesión</h2>

            {flashMessage.message && (
              <div className={`alert-message ${flashMessage.type === 'success' ? 'success' : 'error'}`}>
                {flashMessage.message}
              </div>
            )}

            <div className="input-group">
              <input type="email" name="email" placeholder="Email"
                value={formData.email} onChange={handleChange}
                className={errors.email ? 'error' : ''} required />
              {errors.email && <span className="error-text">{errors.email}</span>}
            </div>

            <div className="input-group">
              <input type="password" name="password" placeholder="Contraseña"
                value={formData.password} onChange={handleChange}
                className={errors.password ? 'error' : ''} required />
              {errors.password && <span className="error-text">{errors.password}</span>}
            </div>

            <button type="button" onClick={handleSubmit}
              disabled={isSubmitting}
              className={`submit-btn ${isSubmitting ? 'loading' : ''}`}>
              {isSubmitting ? "Ingresando..." : "Ingresar"}
            </button>
          </div>

          <div className="welcome-back">
            <div className="message">
              <h2>¿Nuevo aquí?</h2>
              <p>Crea tu cuenta para unirte</p>
              <Link to="/register">
                <button type="button" className="btn-register">Registrarse</button>
              </Link>
            </div>
          </div>
        </div>
      </div>

      {/* Aquí va tu CSS existente (igual que antes) */}
    </div>
  );
};

export default Login;
